      SFETCH_HPSWORD,
      SFETCH_HPSDATA
   );
   signal sectorFetchState          : tsectorFetch := SFETCH_IDLE;

   signal sectorBuffer_addrA        : std_logic_vector(9 downto 0) := (others => '0');
